const ensureAuthStoreDir = () => {
  const dir = path.dirname(AUTH_STORE_FILE);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }
};

const persistPilotsRoster = () => {
  try {
    if (!pilotsRosterCache.data) return;
    ensureAuthStoreDir();
    const tempPath = `${PILOTS_ROSTER_FILE}.tmp`;
    fs.writeFileSync(tempPath, `${JSON.stringify(pilotsRosterCache.data, null, 2)}\n`, "utf8");
    fs.renameSync(tempPath, PILOTS_ROSTER_FILE);
    logger.info('[pilots] persist_success', { PILOTS_ROSTER_FILE });
  } catch (err) {
    logger.warn('[pilots] persist_failed', String(err));
  }
};

const readFleetSnapshotFromDisk = () => {
  try {
    if (!fs.existsSync(FLEET_SNAPSHOT_FILE)) {
      return null;
    }
    const raw = fs.readFileSync(FLEET_SNAPSHOT_FILE, "utf8");
    const parsed = JSON.parse(raw);
    const fleets = Array.isArray(parsed?.fleets) ? parsed.fleets : [];
    return { fleets };
  } catch (err) {
    logger.warn('[fleet] snapshot_read_failed', String(err));
    return null;
  }
};

const persistFleetSnapshot = (payload) => {
  try {
    if (!payload || !Array.isArray(payload?.fleets)) {
      return;
    }
    ensureAuthStoreDir();
    const tempPath = `${FLEET_SNAPSHOT_FILE}.tmp`;
    fs.writeFileSync(tempPath, `${JSON.stringify(payload, null, 2)}\n`, "utf8");
    fs.renameSync(tempPath, FLEET_SNAPSHOT_FILE);
    logger.info('[fleet] snapshot_persist_success', { FLEET_SNAPSHOT_FILE, fleets: payload.fleets.length });
  } catch (err) {
    logger.warn('[fleet] snapshot_persist_failed', String(err));
  }
};

const readDashboardCatalogSnapshotFromDisk = () => {
  try {
    if (!fs.existsSync(DASHBOARD_CATALOG_SNAPSHOT_FILE)) {
      return null;
    }
    const raw = fs.readFileSync(DASHBOARD_CATALOG_SNAPSHOT_FILE, "utf8");
    const parsed = JSON.parse(raw);
    return {
      generatedAt: String(parsed?.generatedAt || "").trim() || null,
      fleets: Array.isArray(parsed?.fleets) ? parsed.fleets : [],
      airports: Array.isArray(parsed?.airports) ? parsed.airports : [],
      routes: Array.isArray(parsed?.routes) ? parsed.routes : [],
    };
  } catch (err) {
    logger.warn("[dashboard] snapshot_read_failed", String(err));
    return null;
  }
};

const persistDashboardCatalogSnapshot = (payload) => {
  try {
    if (!payload || !Array.isArray(payload?.fleets) || !Array.isArray(payload?.airports)) {
      return;
    }
    ensureAuthStoreDir();
    const tempPath = `${DASHBOARD_CATALOG_SNAPSHOT_FILE}.tmp`;
    fs.writeFileSync(tempPath, `${JSON.stringify(payload, null, 2)}\n`, "utf8");
    fs.renameSync(tempPath, DASHBOARD_CATALOG_SNAPSHOT_FILE);
    logger.info("[dashboard] snapshot_persist_success", {
      DASHBOARD_CATALOG_SNAPSHOT_FILE,
      fleets: payload.fleets.length,
      airports: payload.airports.length,
      routes: Array.isArray(payload?.routes) ? payload.routes.length : 0,
    });
  } catch (err) {
    logger.warn("[dashboard] snapshot_persist_failed", String(err));
  }
};

