const isFlightMapEntryAirborne = (flight = {}) => {
  const status = String(flight?.currentPhase || flight?.status || "").trim().toLowerCase();
  if (!status) {
    return false;
  }
  if (/(landed|arrived|completed|cancelled|parked|boarding|scheduled|gate|offline)/.test(status)) {
    return false;
  }
  return /(airborne|depart|takeoff|en route|cruise|climb|descent|approach|taxi out)/.test(status);
};

const buildFlightLogKey = (value = {}) => {
  const bookingId = Number(value?.bookingId || value?.booking_id || 0) || 0;
  const callsign = String(value?.flightNumber || value?.callsign || "").trim().toUpperCase();
  return bookingId > 0 ? `booking:${bookingId}` : callsign ? `callsign:${callsign}` : "";
};

const sweepDiscordFlightLogs = async (settings = getDiscordBotSettingsStore()) => {
  const route = getDiscordAutomationRouteSettings(settings, "flightLogs");
  if (!route?.enabled) {
    return;
  }

  const runtime = getDiscordAutomationRuntime(settings);
  const now = Date.now();
  const pollIntervalMs = Math.max(1, Number(route?.pollIntervalMinutes || 2) || 2) * 60 * 1000;
  const lastPollAt = Number(resolveDiscordAutomationTimestamp(runtime?.lastFlightPollAt) || 0);
  if (lastPollAt > 0 && now - lastPollAt < pollIntervalMs) {
    return;
  }

  const [flightMap, pirepsResponse] = await Promise.all([
    loadFlightMap().catch(() => ({ flights: [] })),
    fetchAllPages("/pireps?page[size]=60&sort=-created_at").catch(() => []),
  ]);

  const activeBefore = new Set(sanitizeDiscordAutomationIdList(runtime?.activeFlightKeys, 400));
  const activeNow = new Set();

  for (const flight of Array.isArray(flightMap?.flights) ? flightMap.flights : []) {
    if (!isFlightMapEntryAirborne(flight)) {
      continue;
    }
    const key = buildFlightLogKey(flight);
    if (!key) {
      continue;
    }
    activeNow.add(key);
    if (activeBefore.has(key)) {
      continue;
    }

    const takeoffCallsign = String(flight?.flightNumber || flight?.callsign || "Flight").trim() || "Flight";
    const takeoffPilot = String(flight?.pilotName || "Pilot").trim() || "Pilot";
    const takeoffDep = String(flight?.departure || "---").trim().toUpperCase();
    const takeoffArr = String(flight?.arrival || "---").trim().toUpperCase();
    await sendDiscordAutomationEventNotification({
      settings,
      routeKey: "flightLogs",
      eventKey: "flightTakeoff",
      title: "Flight departed",
      description: `${takeoffPilot} is now airborne from ${takeoffDep} to ${takeoffArr}.`,
      fields: [
        { name: "Flight", value: takeoffCallsign, inline: true },
        { name: "Route", value: `${takeoffDep}-${takeoffArr}`, inline: true },
        { name: "Phase", value: String(flight?.currentPhase || flight?.status || "En Route").trim() || "En Route", inline: true },
      ],
      variables: { flightNumber: takeoffCallsign, pilotName: takeoffPilot, departure: takeoffDep, arrival: takeoffArr },
    }).catch((error) => {
      logger.warn("[discord-automation] flight_takeoff_send_failed", String(error?.message || error));
    });
    void sendTelegramAdminNotification({
      text: `✈️ *Вылет: ${takeoffCallsign}*\n${takeoffPilot} | ${takeoffDep} → ${takeoffArr}`,
    }).catch(() => {});
  }

  const landedSeen = new Set(sanitizeDiscordAutomationIdList(runtime?.landedPirepIds, 400));
  const recentPireps = Array.isArray(pirepsResponse) ? pirepsResponse.slice(0, 20) : [];
  for (const pirep of recentPireps) {
    const pirepId = String(Number(pirep?.id || 0) || "").trim();
    if (!pirepId || landedSeen.has(pirepId)) {
      continue;
    }
    const landingTimestamp = resolveDiscordAutomationTimestamp(
      pirep?.landing_time,
      pirep?.on_blocks_time,
      pirep?.created_at,
      pirep?.submitted_at
    );
    if (!Number.isFinite(landingTimestamp) || now - landingTimestamp > 6 * 60 * 60 * 1000) {
      continue;
    }

    landedSeen.add(pirepId);
    const landingPilot = String(await loadPilotName(pirep?.pilot_id).catch(() => "Pilot") || "Pilot").trim();
    const landingCallsign = String(pirep?.callsign || pirep?.flight_number || "PIREP").trim() || "PIREP";
    const landingRoute = resolveDiscordAutomationRouteLabel(pirep);
    const landingArr = String(pirep?.arrival_airport?.icao || pirep?.arrival_icao || "---").trim().toUpperCase();
    const landingDep = String(pirep?.departure_airport?.icao || pirep?.departure_icao || "---").trim().toUpperCase();
    const landingRate = Number.isFinite(Number(pirep?.landing_rate)) ? `${Math.round(Number(pirep.landing_rate))} fpm` : "—";
    await sendDiscordAutomationEventNotification({
      settings,
      routeKey: "flightLogs",
      eventKey: "flightLanding",
      title: "Flight landed",
      description: `${landingPilot} landed at ${landingArr} from ${landingDep}.`,
      fields: [
        { name: "Flight", value: landingCallsign, inline: true },
        { name: "Route", value: landingRoute, inline: true },
        { name: "Landing rate", value: landingRate, inline: true },
      ],
      variables: { flightNumber: landingCallsign, pilotName: landingPilot, departure: landingDep, arrival: landingArr, route: landingRoute },
    }).catch((error) => {
      logger.warn("[discord-automation] flight_landing_send_failed", String(error?.message || error));
    });
    void sendTelegramAdminNotification({
      text: `🛬 *Посадка: ${landingCallsign}*\n${landingPilot} | ${landingDep} → ${landingArr} | ${landingRate}`,
    }).catch(() => {});
  }

  // ── PIREP review notifications ─────────────────────────────────────────────
  // Detect PIREPs that entered awaiting_review / manual_review status recently
  // and fire a pirepReview notification (Discord + Telegram) once per PIREP.
  const PIREP_REVIEW_STATUSES = /^(awaiting_review|manual_review|pending_review|review|under_review|pending)$/i;
  const reviewSeen = new Set(sanitizeDiscordAutomationIdList(runtime?.reviewedPirepIds, 400));
  const notificationsSettings = settings?.notifications ?? {};
  const pirepReviewEnabled = notificationsSettings?.pirepReview !== false;

  if (pirepReviewEnabled) {
    for (const pirep of recentPireps) {
      const pirepId = String(Number(pirep?.id || 0) || "").trim();
      if (!pirepId || reviewSeen.has(pirepId)) continue;
      const status = String(pirep?.status || "").trim();
      if (!PIREP_REVIEW_STATUSES.test(status)) continue;

      const submittedAt = resolveDiscordAutomationTimestamp(
        pirep?.submitted_at, pirep?.filed_at, pirep?.created_at, pirep?.updated_at
      );
      if (!Number.isFinite(submittedAt) || now - submittedAt > 6 * 60 * 60 * 1000) continue;

      reviewSeen.add(pirepId);

      const pilotName = String(await loadPilotName(pirep?.pilot_id).catch(() => "") || pirep?.pilot?.name || "Пилот").trim() || "Пилот";
      const callsign = String(pirep?.callsign || pirep?.flight_number || `#${pirepId}`).trim();
      const route = resolveDiscordAutomationRouteLabel(pirep);

      // Discord
      await sendDiscordBotNotification({
        eventKey: "pirepReview",
        title: `PIREP на проверку: ${callsign}`,
        description: `**${pilotName}** подал PIREP по маршруту **${route}**. Статус: \`${status}\``,
        color: 0xf59e0b,
        fields: [
          { name: "Рейс", value: callsign, inline: true },
          { name: "Маршрут", value: route, inline: true },
          { name: "Статус", value: status, inline: true },
        ],
        variables: { pilotName, flightNumber: callsign, route },
      }).catch((err) => {
        logger.warn("[discord-automation] pirep_review_send_failed", String(err?.message || err));
      });

      // Telegram admin notification
      await sendTelegramAdminNotification({
        text: `📋 *PIREP на проверку*\n✈️ ${callsign} | ${route}\n👤 ${pilotName}\nСтатус: \`${status}\``,
      }).catch(() => {});
    }
  }

  updateDiscordAutomationRuntime({
    activeFlightKeys: Array.from(activeNow),
    landedPirepIds: Array.from(landedSeen),
    reviewedPirepIds: Array.from(reviewSeen),
    lastFlightPollAt: new Date(now).toISOString(),
  });
};

const sweepDiscordDailyStats24h = async (settings = getDiscordBotSettingsStore()) => {
  const route = getDiscordAutomationRouteSettings(settings, "dailyStats24h");
  if (!route?.enabled) {
    return;
  }

  const runtime = getDiscordAutomationRuntime(settings);
  const now = new Date();
  const currentMinutes = now.getUTCHours() * 60 + now.getUTCMinutes();
  const targetMinutes = (Math.max(0, Math.min(23, Number(route?.hourUtc || 0) || 0)) * 60) + Math.max(0, Math.min(59, Number(route?.minuteUtc || 0) || 0));
  const dateKey = `${now.getUTCFullYear()}-${String(now.getUTCMonth() + 1).padStart(2, "0")}-${String(now.getUTCDate()).padStart(2, "0")}`;
  if (runtime?.lastDailyStatsDateUtc === dateKey) {
    return;
  }
  if (currentMinutes < targetMinutes || currentMinutes >= targetMinutes + 15) {
    return;
  }

  let sentSuccessfully = false;
  try {
    const snapshot = await buildDailyStats24hSnapshot();
    const windows = Array.isArray(snapshot?.windows) ? snapshot.windows : [];

    const buildWindowFields = (win) => {
      const routes = Array.isArray(win.topRoutes) ? win.topRoutes : [];
      const airports = Array.isArray(win.busiestAirports) ? win.busiestAirports : [];
      const routeLines = routes.length
        ? routes.map((r, i) => `\`${String(i + 1)}.\` **${r.route}** ×${r.count}`).join("\n")
        : "—";
      const airportLines = airports.length
        ? airports.map((a, i) => `\`${String(i + 1)}.\` **${a.icao}** ×${a.count}`).join("\n")
        : "—";
      return [
        {
          name: `✈ ${win.label}  ·  ${win.dateLabel}`,
          value: [
            `**${win.flights}** рейс${win.flights !== 1 ? "ов" : ""}  ·  **${win.flightTime}**  ·  **${win.pilots}** пилот${win.pilots !== 1 ? "ов" : ""}`,
          ].join("\n"),
          inline: false,
        },
        { name: "Топ маршруты", value: routeLines, inline: true },
        { name: "Аэропорты", value: airportLines, inline: true },
        { name: "​", value: "​", inline: false }, // spacer between windows
      ];
    };

    const fields = windows.flatMap(buildWindowFields);
    // Remove trailing spacer
    if (fields.length && fields[fields.length - 1]?.name === "​") fields.pop();

    const result = await sendDiscordPayload({
      channelId: String(route?.channelId || settings?.channels?.news || "").trim(),
      webhookUrl: String(route?.webhookUrl || settings?.webhookUrl || "").trim(),
      payload: {
        allowed_mentions: { parse: [] },
        embeds: [
          {
            title: "📊 Nordwind VA — Статистика",
            color: 0xe31e24,
            fields,
            footer: { text: "Nordwind Virtual Group" },
            timestamp: snapshot.generatedAt,
          },
        ],
      },
    });
    sentSuccessfully = result?.sent === true;
  } catch (error) {
    logger.warn("[discord-automation] daily_stats_send_failed", String(error?.message || error));
  }

  if (sentSuccessfully) {
    updateDiscordAutomationRuntime({
      lastDailyStatsDateUtc: dateKey,
    });
  }
};

const sweepDiscordVatrusNews = async (settings = getDiscordBotSettingsStore()) => {
  const route = getDiscordAutomationRouteSettings(settings, "vatrusNews");
  if (!route?.enabled) {
    return;
  }

  const runtime = getDiscordAutomationRuntime(settings);
  const now = Date.now();
  const pollIntervalMs = Math.max(5, Number(route?.pollIntervalMinutes || 30) || 30) * 60 * 1000;
  const lastPollAt = Number(resolveDiscordAutomationTimestamp(runtime?.lastVatrusPollAt) || 0);
  if (lastPollAt > 0 && now - lastPollAt < pollIntervalMs) {
    return;
  }

  const articles = await loadVatrusNewsFeed(route?.sourceUrl || "https://vatrus.info/news");
  const seen = new Set(sanitizeDiscordAutomationIdList(runtime?.vatrusSeenArticleIds, 400));
  const fresh = articles.filter((article) => article?.id && !seen.has(String(article.id)));

  for (const article of fresh.slice(0, 5).reverse()) {
    await sendDiscordAutomationNotification({
      routeKey: "vatrusNews",
      title: `VATRUS: ${article.title}`,
      description: article.summary || article.eventTime || article.title,
      color: 0x1d4ed8,
      fields: [
        { name: "Published", value: article.publishedAt || "Unknown", inline: true },
        { name: "Event time", value: article.eventTime || "—", inline: true },
        { name: "Region", value: article.region || "—", inline: true },
        { name: "Airport", value: article.airport || "—", inline: true },
        { name: "Link", value: article.url, inline: false },
      ],
    }).catch((error) => {
      logger.warn("[discord-automation] vatrus_news_send_failed", String(error?.message || error));
    });
    seen.add(String(article.id));
  }

  updateDiscordAutomationRuntime({
    vatrusSeenArticleIds: Array.from(seen),
    lastVatrusPollAt: new Date(now).toISOString(),
  });
};

let discordWebhookAutomationTimer = null;
let discordWebhookAutomationSweepPromise = null;

const sweepDiscordWebhookAutomation = async () => {
  if (discordWebhookAutomationSweepPromise) {
    return discordWebhookAutomationSweepPromise;
  }

  discordWebhookAutomationSweepPromise = (async () => {
    const settings = getDiscordBotSettingsStore();
    if (!settings?.enabled) {
      return;
    }

    await Promise.allSettled([
      sweepDiscordFlightLogs(settings),
      sweepDiscordDailyStats24h(settings),
      sweepDiscordVatrusNews(settings),
    ]);
  })().finally(() => {
    discordWebhookAutomationSweepPromise = null;
  });

  return discordWebhookAutomationSweepPromise;
};

const startDiscordWebhookAutomationScheduler = () => {
  if (discordWebhookAutomationTimer) {
    return;
  }

  void sweepDiscordWebhookAutomation().catch((error) => {
    logger.warn("[discord-automation] initial_sweep_failed", String(error?.message || error));
  });
  discordWebhookAutomationTimer = setInterval(() => {
    void sweepDiscordWebhookAutomation().catch((error) => {
      logger.warn("[discord-automation] periodic_sweep_failed", String(error?.message || error));
    });
  }, 60 * 1000);
};

const sendDiscordPayload = async ({ channelId, webhookUrl, payload }) => {
  const normalizedChannelId = String(channelId || "").trim();
  const normalizedWebhookUrl = String(webhookUrl || "").trim();
  const payloadFiles = Array.isArray(payload?.files)
    ? payload.files
        .filter((file) => file && typeof file === "object")
        .map((file, index) => {
          const name = String(file?.name || `attachment-${index + 1}.bin`).trim() || `attachment-${index + 1}.bin`;
          const description = String(file?.description || "").trim();
          const contentType = String(file?.contentType || "application/octet-stream").trim() || "application/octet-stream";
          const rawData = file?.data ?? file?.buffer ?? null;
          const data = Buffer.isBuffer(rawData)
            ? rawData
            : rawData instanceof Uint8Array
              ? Buffer.from(rawData)
              : typeof rawData === "string"
                ? Buffer.from(rawData, "base64")
                : null;
          if (!data || data.length === 0) {
            return null;
          }
          return { name, description, contentType, data };
        })
        .filter(Boolean)
    : [];
  const payloadBody = payload && typeof payload === "object"
    ? {
        ...payload,
        ...(payloadFiles.length > 0
          ? {
              attachments: payloadFiles.map((file, index) => ({
                id: index,
                filename: file.name,
                ...(file.description ? { description: file.description } : {}),
              })),
            }
          : {}),
      }
    : {};
  delete payloadBody.files;
  const buildRequestOptions = (includeAuthorization = false) => {
    if (payloadFiles.length === 0) {
      return {
        headers: {
          ...(includeAuthorization ? { Authorization: `Bot ${DISCORD_BOT_TOKEN}` } : {}),
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payloadBody),
      };
    }

    const form = new FormData();
    form.append("payload_json", JSON.stringify(payloadBody));
    payloadFiles.forEach((file, index) => {
      form.append(
        `files[${index}]`,
        new Blob([file.data], { type: file.contentType }),
        file.name
      );
    });

    return {
      headers: includeAuthorization ? { Authorization: `Bot ${DISCORD_BOT_TOKEN}` } : {},
      body: form,
    };
  };
  let lastError = null;

  if (normalizedChannelId && DISCORD_BOT_TOKEN) {
    const response = await fetch(
      `https://discord.com/api/v10/channels/${encodeURIComponent(normalizedChannelId)}/messages`,
      {
        method: "POST",
        ...buildRequestOptions(true),
      }
    );

    if (response.ok) {
      return { sent: true, via: "bot", channelId: normalizedChannelId };
    }

    lastError = new Error(`Discord API responded with ${response.status}`);
  }

  if (normalizedWebhookUrl) {
    const response = await fetch(normalizedWebhookUrl, {
      method: "POST",
      ...buildRequestOptions(false),
    });

    if (response.ok) {
      return { sent: true, via: "webhook" };
    }

    lastError = new Error(`Discord webhook responded with ${response.status}`);
  }

  if (lastError) {
    throw lastError;
  }

  return { sent: false, reason: "discord_not_configured" };
};

const sendDiscordBotNotification = async ({
  eventKey,
  title,
  description,
  author,
  category,
  color = 0xe31e24,
  fields = [],
  variables = {},
  force = false,
  content = "",
}) => {
  return sendDiscordConfiguredNotification({
    eventKey,
    title,
    description,
    author,
    category,
    color,
    fields,
    variables,
    force,
    content,
  });
};

const sendTelegramPayload = async ({ chatId, text }) => {
  const normalizedChatId = String(chatId || "").trim();
  if (!normalizedChatId) {
    throw new Error("Telegram chat ID is required");
  }
  const normalizedToken = String(TELEGRAM_BOT_TOKEN || "").trim();
  if (!normalizedToken) {
    throw new Error("Telegram bot token is not configured");
  }

  const response = await fetch(`https://api.telegram.org/bot${normalizedToken}/sendMessage`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      chat_id: normalizedChatId,
      text: String(text || "").slice(0, 4096),
      parse_mode: "Markdown",
      disable_web_page_preview: true,
    }),
  });

  const payload = await response.json().catch(() => null);
  if (!response.ok || !payload?.ok) {
    throw new Error(String(payload?.description || `Telegram API responded with ${response.status}`));
  }

  return payload.result || null;
};

const sendTelegramAdminNotification = async ({ text, force = false }) => {
  const settings = getTelegramBotSettingsStore();
  if (!force && settings?.enabled === false) {
    return { sent: false, reason: "disabled", delivered: 0, total: 0 };
  }

  const adminChatIds = (Array.isArray(settings?.adminChatIds) ? settings.adminChatIds : [])
    .map((item) => String(item || "").trim())
    .filter(Boolean);

  if (!adminChatIds.length) {
    return { sent: false, reason: "admin_chats_not_configured", delivered: 0, total: 0 };
  }

  const results = await Promise.allSettled(
    adminChatIds.map((chatId) => sendTelegramPayload({ chatId, text }))
  );
  const delivered = results.filter((item) => item.status === "fulfilled").length;

  if (delivered <= 0) {
    const rejected = results.find((item) => item.status === "rejected");
    throw new Error(String(rejected?.reason?.message || rejected?.reason || "Failed to send Telegram notification"));
  }

  return {
    sent: true,
    delivered,
    total: adminChatIds.length,
  };
};

const buildTelegramTicketAdminNotificationText = ({ eventKey = "ticketUpdated", ticket = {}, actorName = "", content = "" } = {}) => {
  const title = eventKey === "ticketCreated"
    ? "Новый тикет из Telegram"
    : eventKey === "ticketReply"
      ? "Ответ в тикете из Telegram"
      : eventKey === "ticketClosed"
        ? "Тикет закрыт из Telegram"
        : "Тикет обновлён из Telegram";
  const subject = normalizeAdminText(ticket?.subject || "") || "Без темы";
  const category = normalizeAdminText(ticket?.categoryName || ticket?.categoryId || "") || "—";
  const priority = normalizeTicketPriority(ticket?.priority, "normal");
  const status = normalizeTicketStatus(ticket?.status, "open");
  const route = `#${Number(ticket?.number || 0) || "?"} • ${subject}`;
  const author = normalizeAdminText(actorName || ticket?.owner?.name || ticket?.owner?.username || "") || "Telegram user";
  const summary = normalizeAdminMultilineText(content || "").slice(0, 400);

  const ticketNum = Number(ticket?.number || 0) || null;
  return [
    title,
    route,
    `Автор: ${author}`,
    `Категория: ${category}`,
    `Приоритет: ${priority}`,
    `Статус: ${status}`,
    summary ? `Сообщение: ${summary}` : null,
    ticketNum && (eventKey === "ticketCreated" || eventKey === "ticketReply")
      ? `\n📩 /reply ${ticketNum} <ваш ответ>`
      : null,
    ticketNum && eventKey === "ticketCreated"
      ? `🔒 /close ${ticketNum}`
      : null,
  ].filter(Boolean).join("\n");
};

const sendTelegramTicketAdminNotification = async ({ eventKey = "ticketUpdated", ticket = {}, actorName = "", content = "" } = {}) => {
  const settings = getTelegramBotSettingsStore();
  if (settings?.enabled === false) {
    return { sent: false, reason: "disabled", delivered: 0, total: 0 };
  }
  if (settings?.sync?.tickets === false) {
    return { sent: false, reason: "ticket_sync_disabled", delivered: 0, total: 0 };
  }

  return sendTelegramAdminNotification({
    text: buildTelegramTicketAdminNotificationText({ eventKey, ticket, actorName, content }),
  });
};

