const AI_UNAVAILABLE_REPLY = {
  ru: "Помощник временно недоступен — попробуйте чуть позже или обратитесь к команде напрямую.",
  en: "The assistant is temporarily unavailable — please try again later or contact the team directly.",
};

// Последняя ошибка AI — видна только в /api/admin/ai/status
let aiLastError = null;

const callClaudeAI = async (messages, lang = "ru") => {
  const unavailable = (hint) => {
    aiLastError = { reason: hint, at: new Date().toISOString() };
    logger.warn("[ai-chat] unavailable:", hint);
    return { reply: lang === "en" ? AI_UNAVAILABLE_REPLY.en : AI_UNAVAILABLE_REPLY.ru, escalate: false, unavailable: true };
  };

  if (!ANTHROPIC_API_KEY) return unavailable("no_api_key");

  // buildAiSiteContext() использует in-memory кэш (TTL 1ч, диск при старте) — реального API не вызывает
  const knowledgeText = typeof buildAiSiteContext === "function"
    ? await buildAiSiteContext().catch(() => getAiKnowledgeText())
    : getAiKnowledgeText();
  const systemPrompt = knowledgeText
    ? `${VA_AI_SYSTEM_PROMPT}\n\n${knowledgeText}`
    : VA_AI_SYSTEM_PROMPT;

  let response;
  try {
    response = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": ANTHROPIC_API_KEY,
        "anthropic-version": "2023-06-01",
      },
      body: JSON.stringify({
        model: "claude-sonnet-4-6",
        max_tokens: 1024,
        system: systemPrompt,
        messages: messages.map((m) => ({
          role: m.role === "user" ? "user" : "assistant",
          content: String(m.content || "").slice(0, 4000),
        })),
      }),
    });
  } catch (fetchErr) {
    return unavailable(`fetch_error: ${String(fetchErr)}`);
  }

  if (!response.ok) {
    const err = await response.json().catch(() => ({}));
    const status = response.status;
    // 401 = invalid key, 403 = forbidden, 429 = rate limit / quota, 529 = overloaded
    if (status === 401 || status === 403 || status === 429 || status === 529 || status >= 500) {
      return unavailable(`http_${status}: ${String(err?.error?.message || "")}`);
    }
    return unavailable(`http_${status}`);
  }

  const data = await response.json();
  const text = data?.content?.[0]?.text || "";
  const escalate = /\[ESCALATE\]/.test(text);
  const reply = text.replace(/\[ESCALATE\]/g, "").trim();
  aiLastError = null; // сброс — последний вызов был успешным
  return { reply, escalate };
};

const createAiEscalationTicket = ({ subject, content, owner, lang } = {}) => {
  const config = getTicketConfigStore();
  if (!config.enabled) return null;

  const categories = Array.isArray(config.categories) ? config.categories : [];
  const category = categories.find((c) =>
    /support|поддержк|general|общ/i.test(String(c?.name || c?.id || ""))
  ) || categories[0] || null;
  if (!category) return null;

  const now = new Date().toISOString();
  const ticket = {
    id: randomUUID(),
    number: getNextTicketNumber(),
    subject: normalizeAdminText(subject || "Запрос оператора через AI-помощника").slice(0, 200) || "Запрос оператора",
    categoryId: category.id,
    categoryName: category.name,
    status: "open",
    priority: "normal",
    tags: [],
    assigneeId: null,
    assigneeName: null,
    owner: {
      pilotId: owner?.pilotId || null,
      telegramId: owner?.telegramId || null,
      telegramChatId: owner?.telegramChatId || null,
      username: normalizeAdminText(owner?.username || "") || "ai-assistant",
      name: normalizeAdminText(owner?.name || "") || "AI Помощник",
      provider: owner?.provider || "ai-assistant",
    },
    messages: [
      {
        id: randomUUID(),
        authorRole: "pilot",
        authorName: normalizeAdminText(owner?.name || "") || "Пользователь",
        authorUsername: normalizeAdminText(owner?.username || "") || "ai-assistant",
        content: normalizeAdminMultilineText(content || "").slice(0, 4000) || "Пользователь запросил оператора через AI-помощника",
        createdAt: now,
      },
    ],
    unreadByOwner: 0,
    unreadByStaff: 1,
    createdAt: now,
    updatedAt: now,
    closedAt: null,
    language: lang || null,
    source: owner?.provider || "ai-assistant",
    telegramChatId: owner?.telegramChatId || null,
  };

  withAdminContentUpdate((draft) => {
    const items = Array.isArray(draft?.tickets) ? [...draft.tickets] : [];
    items.push(ticket);
    draft.tickets = items;
    return draft;
  });

  return ticket;
};

const notifyAiEscalation = async ({ ticket, conversationSummary = "" } = {}) => {
  const subject = normalizeAdminText(ticket?.subject || "Запрос оператора");
  const number = ticket?.number || "?";
  const name = normalizeAdminText(ticket?.owner?.name || ticket?.owner?.username || "Пользователь");
  const source = normalizeAdminText(ticket?.source || "ai-assistant");

  const tgText = [
    `🤖 *Запрос оператора #${number}*`,
    `Источник: ${source}`,
    `Пользователь: ${name}`,
    `Тема: ${subject}`,
    conversationSummary ? `Контекст: ${conversationSummary.slice(0, 300)}` : null,
    `Тикет #${number} открыт — ответьте в панели администратора`,
  ].filter(Boolean).join("\n");

  await sendTelegramAdminNotification({ text: tgText }).catch(() => {});

  const discordPayload = {
    embeds: [{
      title: `🤖 Запрос оператора #${number}`,
      description: `Пользователь запросил живого оператора через AI-помощника.`,
      color: 0xe31e24,
      fields: [
        { name: "Пользователь", value: name, inline: true },
        { name: "Источник", value: source, inline: true },
        { name: "Тема", value: subject, inline: false },
        conversationSummary ? { name: "Контекст", value: conversationSummary.slice(0, 500), inline: false } : null,
      ].filter(Boolean),
      timestamp: new Date().toISOString(),
    }],
  };

  const settings = getDiscordBotSettingsStore();
  const channelId = settings?.alertsChannelId || settings?.channelId || "";
  const webhookUrl = settings?.webhookUrl || "";
  if (channelId || webhookUrl) {
    await sendDiscordPayload({ channelId, webhookUrl, payload: discordPayload }).catch(() => {});
  }
};

// Telegram long-polling loop — runs inside this server process
let telegramPollingOffset = 0;
let telegramPollingActive = false;
let telegramPollingAbort = null;

const handleTelegramMessage = async (update) => {
  const message = update?.message;
  if (!message) return;

  const chatId = String(message?.chat?.id || "");
  const text = String(message?.text || "").trim();
  const username = normalizeAdminText(message?.from?.username || "");
  const firstName = normalizeAdminText(message?.from?.first_name || "");
  const telegramId = String(message?.from?.id || "");

  if (!chatId || !text) return;

  const settings = getTelegramBotSettingsStore();
  if (settings?.enabled === false) return;

  // ── Built-in command shortcuts ─────────────────────────────
  if (text === "/start" || text === "/help") {
    const isAdmin = isTelegramBotAdminChat(chatId);
    const reply = [
      "Привет! Я AI-помощник Nordwind Virtual 🤖",
      "",
      "Команды:",
      "/link — привязать аккаунт vAMSYS",
      "/profile — профиль пилота",
      "/booking — текущее бронирование",
      "/news — последние новости",
      "/ticket — создать тикет",
      "/metar ICAO — погода",
      ...(isAdmin ? [
        "",
        "Команды стаффа:",
        "/reply <номер> <текст> — ответить в тикет",
        "/close <номер> — закрыть тикет",
      ] : []),
      "",
      "Или просто задай вопрос — я отвечу на русском или английском.",
    ].join("\n");
    await sendTelegramPayload({ chatId, text: reply }).catch(() => {});
    return;
  }

  // ── Staff: /reply <номер> <текст> ─────────────────────────
  if (text.startsWith("/reply ") || text.startsWith("/ответить ")) {
    if (!isTelegramBotAdminChat(chatId)) {
      await sendTelegramPayload({ chatId, text: "⛔ Только для стаффа." }).catch(() => {});
      return;
    }
    const parts = text.replace(/^\/\S+\s+/, "").match(/^(\d+)\s+([\s\S]+)$/);
    if (!parts) {
      await sendTelegramPayload({ chatId, text: "Формат: /reply <номер тикета> <текст ответа>" }).catch(() => {});
      return;
    }
    const [, ticketNumberStr, replyContent] = parts;
    const ticketNumber = Number(ticketNumberStr);
    const staffName = firstName || username || "Staff";
    let updatedTicket = null;

    withAdminContentUpdate((draft) => {
      const items = Array.isArray(draft?.tickets) ? [...draft.tickets] : [];
      const index = items.findIndex((t) => Number(t?.number || 0) === ticketNumber);
      if (index < 0) return draft;
      const current = items[index];
      const now = new Date().toISOString();
      const nextMessages = Array.isArray(current?.messages) ? [...current.messages] : [];
      nextMessages.push({
        id: randomUUID(),
        authorRole: "staff",
        authorName: staffName,
        authorUsername: username || "staff",
        content: normalizeAdminMultilineText(replyContent),
        createdAt: now,
      });
      updatedTicket = {
        ...current,
        messages: nextMessages,
        status: current?.status === "closed" ? "open" : normalizeTicketStatus(current?.status, "open"),
        updatedAt: now,
        closedAt: current?.status === "closed" ? null : (current?.closedAt || null),
        unreadByOwner: Number(current?.unreadByOwner || 0) + 1,
        unreadByStaff: 0,
      };
      items[index] = updatedTicket;
      draft.tickets = items;
      return draft;
    });

    if (!updatedTicket) {
      await sendTelegramPayload({ chatId, text: `❌ Тикет #${ticketNumber} не найден.` }).catch(() => {});
      return;
    }

    await sendTelegramPayload({ chatId, text: `✅ Ответ добавлен в тикет #${ticketNumber}.` }).catch(() => {});

    // Уведомить пилота, если у него есть Telegram chatId
    const ownerChatId = normalizeAdminText(updatedTicket?.telegramChatId || updatedTicket?.owner?.telegramChatId || "");
    if (ownerChatId) {
      const pilotText = [
        `📋 Ответ в тикете #${updatedTicket.number}: ${updatedTicket.subject}`,
        `От: ${staffName}`,
        "",
        replyContent.slice(0, 800),
      ].join("\n");
      await sendTelegramPayload({ chatId: ownerChatId, text: pilotText }).catch(() => {});
    }
    return;
  }

  // ── Staff: /close <номер> ──────────────────────────────────
  if (text.startsWith("/close ") || text.startsWith("/закрыть ")) {
    if (!isTelegramBotAdminChat(chatId)) {
      await sendTelegramPayload({ chatId, text: "⛔ Только для стаффа." }).catch(() => {});
      return;
    }
    const ticketNumber = Number(text.replace(/^\/\S+\s+/, "").trim());
    if (!ticketNumber) {
      await sendTelegramPayload({ chatId, text: "Формат: /close <номер тикета>" }).catch(() => {});
      return;
    }
    const staffName = firstName || username || "Staff";
    let updatedTicket = null;

    withAdminContentUpdate((draft) => {
      const items = Array.isArray(draft?.tickets) ? [...draft.tickets] : [];
      const index = items.findIndex((t) => Number(t?.number || 0) === ticketNumber);
      if (index < 0) return draft;
      const now = new Date().toISOString();
      updatedTicket = { ...items[index], status: "closed", updatedAt: now, closedAt: now, unreadByOwner: Number(items[index]?.unreadByOwner || 0) + 1 };
      items[index] = updatedTicket;
      draft.tickets = items;
      return draft;
    });

    if (!updatedTicket) {
      await sendTelegramPayload({ chatId, text: `❌ Тикет #${ticketNumber} не найден.` }).catch(() => {});
      return;
    }

    await sendTelegramPayload({ chatId, text: `✅ Тикет #${ticketNumber} закрыт.` }).catch(() => {});

    const ownerChatId = normalizeAdminText(updatedTicket?.telegramChatId || updatedTicket?.owner?.telegramChatId || "");
    if (ownerChatId) {
      await sendTelegramPayload({ chatId: ownerChatId, text: `📋 Ваш тикет #${updatedTicket.number} закрыт стаффом. Если вопрос не решён — создайте новый тикет.` }).catch(() => {});
    }
    return;
  }

  if (text.startsWith("/")) return; // Другие команды — пусть внешний бот обработает

  // ── AI response ───────────────────────────────────────────
  if (!ANTHROPIC_API_KEY) return; // AI не настроен, молчим

  try {
    const tgMessages = [{ role: "user", content: text }];
    const tgCacheKey = buildAiCacheKey(tgMessages);
    const tgCached = getAiCached(tgCacheKey);

    let reply, escalate;
    if (tgCached && !tgCached.escalate) {
      ({ reply, escalate } = { reply: tgCached.reply, escalate: false });
    } else {
      ({ reply, escalate } = await callClaudeAI(tgMessages));
      if (!escalate && reply) setAiCached(tgCacheKey, reply, false);
    }

    if (escalate) {
      const ticket = createAiEscalationTicket({
        subject: text.slice(0, 100),
        content: `Telegram-пользователь @${username || telegramId} запросил оператора.\n\nСообщение: ${text}`,
        owner: {
          telegramId,
          telegramChatId: chatId,
          username: username || telegramId,
          name: firstName || username || "Telegram User",
          provider: "telegram",
        },
        lang: "ru",
      });

      if (ticket) {
        await notifyAiEscalation({ ticket, conversationSummary: text });
      }

      const escalateReply = reply
        ? `${reply}\n\n📋 Тикет #${ticket?.number || "?"} создан — оператор скоро ответит.`
        : `Понял, передаю оператору! 📋 Тикет #${ticket?.number || "?"} создан — мы ответим в ближайшее время.`;
      await sendTelegramPayload({ chatId, text: escalateReply }).catch(() => {});
      return;
    }

    if (reply) {
      await sendTelegramPayload({ chatId, text: reply }).catch(() => {});
    }
  } catch (err) {
    logger.warn("[ai-telegram] response_failed", String(err?.message || err));
  }
};

const runTelegramPollingTick = async () => {
  const token = String(TELEGRAM_BOT_TOKEN || "").trim();
  if (!token) return;

  const url = `https://api.telegram.org/bot${token}/getUpdates?offset=${telegramPollingOffset}&timeout=25&allowed_updates=["message"]`;

  let data;
  try {
    const controller = new AbortController();
    telegramPollingAbort = controller;
    const response = await fetch(url, { signal: controller.signal });
    telegramPollingAbort = null;
    if (!response.ok) return;
    data = await response.json();
  } catch {
    telegramPollingAbort = null;
    return;
  }

  if (!data?.ok || !Array.isArray(data.result)) return;

  for (const update of data.result) {
    const updateId = Number(update?.update_id || 0);
    if (updateId >= telegramPollingOffset) {
      telegramPollingOffset = updateId + 1;
    }
    await handleTelegramMessage(update).catch(() => {});
  }
};

const startTelegramPollingLoop = () => {
  const token = String(TELEGRAM_BOT_TOKEN || "").trim();
  if (!token || telegramPollingActive) return;

  telegramPollingActive = true;
  logger.info("[telegram-polling] started");

  const loop = async () => {
    while (telegramPollingActive) {
      await runTelegramPollingTick().catch(() => {});
      if (telegramPollingActive) {
        await new Promise((resolve) => setTimeout(resolve, 500));
      }
    }
  };

  loop().catch(() => {});
};

// getAiKnowledgeText — мост к aiKnowledgeCache (заполняется buildAiSiteContext ниже).
// Возвращает закэшированный snapshot или пустую строку если ещё не готов.
const getAiKnowledgeText = () => aiKnowledgeCache?.text || "";

// ─── AI response cache ───────────────────────────────────────────────────────

const AI_CACHE_TTL_MS = 7 * 24 * 60 * 60 * 1000; // 7 days
const AI_CACHE_MAX_ENTRIES = 2000;
const AI_CACHE_FILE = path.join(path.dirname(AUTH_STORE_FILE), "ai-response-cache.json");

const aiResponseCache = new Map(); // key → { reply, escalate, cachedAt }

const loadAiResponseCache = () => {
  try {
    if (!fs.existsSync(AI_CACHE_FILE)) return;
    const raw = fs.readFileSync(AI_CACHE_FILE, "utf8");
    const entries = JSON.parse(raw);
    const now = Date.now();
    let loaded = 0;
    for (const [k, v] of Object.entries(entries)) {
      if (v && typeof v === "object" && now - Number(v.cachedAt || 0) < AI_CACHE_TTL_MS) {
        aiResponseCache.set(k, v);
        loaded++;
      }
    }
    logger.info("[ai-cache] loaded", { entries: loaded });
  } catch {
    /* ignore */
  }
};

const persistAiResponseCache = () => {
  try {
    const now = Date.now();
    const obj = {};
    for (const [k, v] of aiResponseCache.entries()) {
      if (now - Number(v.cachedAt || 0) < AI_CACHE_TTL_MS) obj[k] = v;
    }
    fs.writeFileSync(AI_CACHE_FILE, JSON.stringify(obj), "utf8");
  } catch {
    /* ignore */
  }
};

const buildAiCacheKey = (messages) => {
  // Normalize: lowercase, collapse whitespace, trim
  const normalized = messages
    .map((m) => `${m.role}:${String(m.content || "").toLowerCase().trim().replace(/\s+/g, " ")}`)
    .join("|");
  return createHash("sha256").update(normalized).digest("hex").slice(0, 32);
};

const getAiCached = (key) => {
  const entry = aiResponseCache.get(key);
  if (!entry) return null;
  if (Date.now() - Number(entry.cachedAt || 0) > AI_CACHE_TTL_MS) {
    aiResponseCache.delete(key);
    return null;
  }
  return entry;
};

const setAiCached = (key, reply, escalate) => {
  // Evict oldest entries if over limit
  if (aiResponseCache.size >= AI_CACHE_MAX_ENTRIES) {
    const oldest = [...aiResponseCache.entries()].sort((a, b) => Number(a[1].cachedAt) - Number(b[1].cachedAt));
    for (let i = 0; i < Math.floor(AI_CACHE_MAX_ENTRIES * 0.1); i++) {
      aiResponseCache.delete(oldest[i][0]);
    }
  }
  aiResponseCache.set(key, { reply, escalate, cachedAt: Date.now() });
  // Persist async
  setImmediate(() => persistAiResponseCache());
};

// Load cache on startup
loadAiResponseCache();
// Persist cache every 10 minutes to protect against crashes
setInterval(() => persistAiResponseCache(), 10 * 60 * 1000).unref();

