app.post("/api/pilot/routes/:id/report-outdated", async (req, res) => {
  const context = await resolveCurrentPilotContext(req).catch(() => null);
  if (!context?.pilotId && !context?.pilot?.username) {
    res.status(401).json({ ok: false, error: "Authentication required", code: "auth_required" });
    return;
  }

  const routeId = Number(req.params.id || 0) || 0;
  if (routeId <= 0) {
    res.status(400).json({ ok: false, error: "Route ID is required", code: "route_id_required" });
    return;
  }

  try {
    const routesPayload = await loadRoutesData();
    const route = (Array.isArray(routesPayload?.routes) ? routesPayload.routes : []).find(
      (item) => Number(item?.id || 0) === routeId
    );

    if (!route) {
      res.status(404).json({ ok: false, error: "Route not found", code: "route_not_found" });
      return;
    }

    // Moderation: blocklist, cooldown and daily limit (duplicates handled inside create)
    const reportOwner = resolvePilotSupportTicketOwner(context);
    const reportSettings = getRouteReportSettingsStore();

    const blockEntry = findRouteReportBlockEntry(reportOwner, reportSettings);
    if (blockEntry) {
      res.status(403).json({ ok: false, code: "report_blocked", error: "Route reports are blocked for your account" });
      return;
    }

    const existingDuplicate = findActiveOutdatedRouteReportTicket(listTicketsStore(), route?.id, reportOwner);
    if (!existingDuplicate) {
      const usage = getRouteReportUsage(reportOwner);
      if (reportSettings.cooldownMinutes > 0 && usage.lastAt > 0) {
        const elapsedMs = Date.now() - usage.lastAt;
        const cooldownMs = reportSettings.cooldownMinutes * 60 * 1000;
        if (elapsedMs < cooldownMs) {
          const retryMinutes = Math.max(1, Math.ceil((cooldownMs - elapsedMs) / 60000));
          res.status(429).json({ ok: false, code: "report_cooldown", retryMinutes, error: `Please wait ${retryMinutes} min before sending another report` });
          return;
        }
      }
      if (reportSettings.dailyLimit > 0 && usage.last24h >= reportSettings.dailyLimit) {
        res.status(429).json({ ok: false, code: "report_daily_limit", error: "Daily route report limit reached" });
        return;
      }
    }

    const result = createOutdatedRouteReportTicket({
      route,
      context,
      reason: String(req.body?.reason || "").slice(0, 200),
      comment: String(req.body?.comment || "").slice(0, 500),
    });
    if (result.error) {
      res.status(503).json({ ok: false, error: result.error, code: "ticket_unavailable" });
      return;
    }

    res.status(result.duplicate ? 200 : 201).json({
      ok: true,
      duplicate: result.duplicate,
      ticket: result.ticket,
    });
  } catch (error) {
    res.status(502).json({ ok: false, error: String(error?.message || "Failed to submit outdated flight report"), code: "route_report_failed" });
  }
});

app.get("/api/vamsys/notams", async (req, res) => {
  if (!requireCredentials(res)) {
    return;
  }

  try {
    const context = await resolveCurrentPilotContext(req).catch(() => null);
    const payload = await fetchNotamsPages();
    const notams = (Array.isArray(payload) ? payload : [])
      .map((item) => serializeVamsysNotam(item))
      .map((item) => ({
        ...item,
        isOpened: context?.pilot ? hasPilotOpenedNotam(context.pilot, item.id) : false,
        openedAt: context?.pilot ? getPilotNotamStateEntry(context.pilot, item.id)?.openedAt || null : null,
        isRead: context?.pilot ? hasPilotReadNotam(context.pilot, item.id) : false,
      }))
      .sort((left, right) => {
        const leftTime = Date.parse(String(left?.createdAt || ""));
        const rightTime = Date.parse(String(right?.createdAt || ""));
        return (Number.isFinite(rightTime) ? rightTime : 0) - (Number.isFinite(leftTime) ? leftTime : 0);
      });

    const unread = context?.pilot ? getUnreadNotamsForPilot(context.pilot, notams) : [];

    res.json({
      notams,
      summary: {
        total: notams.length,
        mustRead: notams.filter((item) => item.mustRead).length,
        highPriority: notams.filter((item) => item.priority === "high").length,
        unread: unread.length,
        unreadMustRead: unread.filter((item) => item.mustRead).length,
      },
    });
  } catch (error) {
    res.status(502).json({
      error: String(error?.message || "Failed to load vAMSYS NOTAMs"),
    });
  }
});

