app.post("/api/admin/alerts", async (req, res) => {
  if (!requireCredentials(res)) {
    return;
  }

  try {
    const payload = await apiRequest("/alerts", {
      method: "POST",
      body: buildAdminAlertPayload(req.body || {}),
    });
    if (normalizeAdminBoolean(req.body?.sendToDiscord ?? req.body?.publishToDiscord, false)) {
      void sendDiscordBotNotification({
        eventKey: "alertCreated",
        title: String(req.body?.title || "Untitled Alert"),
        description: String(req.body?.content || "").trim(),
        category: "ALERT",
        author: "Ops",
        color: 0x3b82f6,
        variables: {
          title: String(req.body?.title || "Untitled Alert"),
          content: String(req.body?.content || "").trim(),
          pages: Array.isArray(req.body?.pages) ? req.body.pages.join(", ") : "dashboard",
        },
        fields: [
          {
            name: "Pages",
            value: Array.isArray(req.body?.pages) && req.body.pages.length > 0 ? req.body.pages.join(", ") : "dashboard",
            inline: true,
          },
        ],
      }).catch(() => {});
    }
    if (normalizeAdminBoolean(req.body?.sendToVK, false) && getVkBotSettingsStore()?.sync?.alerts !== false) {
      void publishNewsToVk({
        title: String(req.body?.title || "Untitled Alert"),
        content: String(req.body?.content || "").trim(),
        category: "ALERT",
        author: "Ops",
        linkUrl: normalizeAdminText(req.body?.linkUrl || req.body?.url),
        bannerUrl: normalizeAdminText(req.body?.bannerUrl || req.body?.imageUrl || req.body?.image),
      }).catch(() => {});
    }
    if (normalizeAdminBoolean(req.body?.sendToTelegram, false) && getTelegramBotSettingsStore()?.sync?.alerts !== false) {
      const alertTitle = String(req.body?.title || "Alert").slice(0, 120);
      const alertBody = String(req.body?.content || "").trim().slice(0, 280);
      void sendTelegramAdminNotification({
        text: `🔔 *Алерт: ${alertTitle}*${alertBody ? "\n" + alertBody : ""}`,
      }).catch(() => {});
    }
    res.json(payload);
  } catch (error) {
    res.status(502).json({
      error: String(error?.message || "Failed to create alert"),
    });
  }
});

