app.get("/api/public/news", (_req, res) => {
  try {
    const news = listManagedAdminCollection("activities")
      .filter((item) => normalizeAdminBoolean(item?.published, true))
      .filter((item) => normalizePublicActivityStatus(item?.status, "Published") === "Published")
      .filter((item) => normalizePublicActivityCategory(item?.category || item?.type) === "News")
      .map((item) => toPublicManualActivity(item))
      .sort((left, right) => {
        const orderDiff = Number(Boolean(right?.featured)) - Number(Boolean(left?.featured));
        if (orderDiff !== 0) {
          return orderDiff;
        }
        const rightTime = Date.parse(String(right?.date || ""));
        const leftTime = Date.parse(String(left?.date || ""));
        return (Number.isFinite(rightTime) ? rightTime : 0) - (Number.isFinite(leftTime) ? leftTime : 0);
      });

    res.json({ news });
  } catch (error) {
    res.status(502).json({ error: String(error || "Failed to load public news") });
  }
});

app.get("/api/public/activities", async (_req, res) => {
  try {
    const manualActivities = listManagedAdminCollection("activities")
      .filter((item) => normalizeAdminBoolean(item?.published, true))
      .filter((item) => normalizePublicActivityStatus(item?.status, "Published") === "Published")
      .filter((item) => normalizePublicActivityCategory(item?.category || item?.type) === "Event")
      .map((item) => toPublicManualActivity(item));

    const liveCatalog = await loadAdminActivitiesCatalog().catch(() => ({ activities: [] }));
    const liveActivities = (Array.isArray(liveCatalog?.activities) ? liveCatalog.activities : [])
      .filter((item) => String(item?.status || "") !== "ended")
      .map((item) => toPublicLiveActivity(item));

    const liveIds = new Set(
      liveActivities
        .map((item) => Number(item?.originalId || 0) || 0)
        .filter((id) => id > 0)
    );

    const manualFallbackActivities = manualActivities.filter((item) => {
      const linkedId = Number(item?.originalId || 0) || 0;
      if (linkedId <= 0) {
        return true;
      }
      return !liveIds.has(linkedId);
    });

    const slottedEventsRaw = await getCachedSlottedEvents().catch(() => []);
    const slottedEvents = (Array.isArray(slottedEventsRaw) ? slottedEventsRaw : [])
      .map((item) => flattenSlottedEvent({ data: item }))
      .filter((ev) => !ev.hidden && ev.name && ev.id > 0)
      .map((ev) => ({
        id: `slotted-${ev.id}`,
        source: "vamsys",
        originalId: ev.id,
        category: "Event",
        title: ev.name,
        content: ev.description || ev.name,
        summary: ev.description || null,
        author: "vAMSYS",
        date: ev.start || ev.showFrom || new Date().toISOString(),
        status: "Published",
        views: ev.registrationCount,
        tag: ev.departureAirport
          ? `${ev.departureAirport}${ev.arrivalAirport ? ` → ${ev.arrivalAirport}` : ""}`
          : null,
        linkUrl: `/activities/slotted/${ev.id}`,
        featured: false,
        activityType: "SlottedEvent",
        activitySubtype: ev.slotInterval ? `${ev.slotInterval} min/slot` : null,
        target: null,
        imageUrl: ev.image || null,
        registrationOpen: true,
        registrations: ev.registrationCount,
        completions: 0,
        points: ev.points,
        start: ev.start,
        end: ev.end,
        showFrom: ev.showFrom,
        tags: [],
      }));

    const activities = [...liveActivities, ...manualFallbackActivities, ...slottedEvents].sort((left, right) => {
      const orderDiff = Number(Boolean(right?.featured)) - Number(Boolean(left?.featured));
      if (orderDiff !== 0) {
        return orderDiff;
      }
      const rightTime = Date.parse(String(right?.date || ""));
      const leftTime = Date.parse(String(left?.date || ""));
      return (Number.isFinite(rightTime) ? rightTime : 0) - (Number.isFinite(leftTime) ? leftTime : 0);
    });

    res.json({ activities });
  } catch (error) {
    res.status(502).json({ error: String(error || "Failed to load public activities") });
  }
});

// ── Единая лента активности сообщества (сайт + приложение) ──
// Агрегирует: галерея (загрузки/лайки/альбомы), завершённые рейсы (кто куда летал),
// новости и события. Нормализует к общему виду и сортирует по времени. Публичный.
const FEED_VAC_FROM_CALLSIGN = (callsign) => {
  const s = String(callsign || "").toUpperCase();
  if (s.includes("KAR")) return "KAR";
  if (s.includes("STW")) return "STW";
  return "NWS";
};

app.get("/api/feed", async (req, res) => {
  const limit = Math.max(1, Math.min(60, Number(req.query.limit || 30) || 30));
  const items = [];

  // 1) Галерея — загрузки/лайки/альбомы (viewer=null → только публичное).
  try {
    const store = readSocialGalleryStore();
    for (const entry of buildSocialGalleryFeed(store, null, 30)) {
      const media = entry.media || null;
      items.push({
        id: `gallery:${entry.id}`,
        type: entry.type === "like" ? "like" : entry.type === "album" ? "album" : "screenshot",
        createdAt: entry.createdAt || null,
        actor: entry.actor || null,
        title: entry.title || "",
        summary: entry.summary || "",
        media: media ? { url: media.url || media.assetUrl || null, likeCount: Number(media.likeCount || 0) || 0 } : null,
        route: null,
        vac: null,
        href: "/gallery",
      });
    }
  } catch { /* ignore source */ }

  // 2) Завершённые рейсы — «кто куда летал».
  if ((CLIENT_ID && CLIENT_SECRET) || API_TOKEN) {
    try {
      const { flights } = await loadCompletedFlights({ limit: 24 });
      for (const f of Array.isArray(flights) ? flights : []) {
        const createdAt = f.completedDate ? `${f.completedDate}T${f.completedTime || "00:00:00"}Z` : null;
        items.push({
          id: `flight:${f.id || `${f.flightNumber}-${createdAt}`}`,
          type: "flight",
          createdAt,
          actor: { name: f.pilot || "Pilot", pilotId: f.pilotId || null, username: null },
          title: f.flightNumber || "—",
          summary: `${f.departureCity || f.departure} → ${f.destinationCity || f.destination}${f.aircraft ? ` · ${f.aircraft}` : ""}`,
          media: null,
          route: { from: f.departure || "—", to: f.destination || "—" },
          vac: f.vac || FEED_VAC_FROM_CALLSIGN(f.flightNumber),
          href: "/dashboard?tab=recent",
        });
      }
    } catch { /* ignore source */ }
  }

  // 3) Новости + события (из админ-коллекции activities).
  try {
    const managed = listManagedAdminCollection("activities")
      .filter((item) => normalizeAdminBoolean(item?.published, true))
      .filter((item) => normalizePublicActivityStatus(item?.status, "Published") === "Published")
      .map((item) => ({ pub: toPublicManualActivity(item), cat: normalizePublicActivityCategory(item?.category || item?.type) }))
      .filter((x) => x.cat === "News" || x.cat === "Event");
    for (const { pub, cat } of managed) {
      const isEvent = cat === "Event";
      items.push({
        id: `${isEvent ? "event" : "news"}:${pub.id || pub.slug || pub.title}`,
        type: isEvent ? "event" : "news",
        createdAt: pub.date || null,
        actor: pub.author ? { name: pub.author, pilotId: null, username: null } : null,
        title: pub.title || (isEvent ? "Event" : "News"),
        summary: pub.summary || "",
        media: pub.imageUrl ? { url: pub.imageUrl, likeCount: 0 } : null,
        route: null,
        vac: null,
        href: isEvent ? "/events" : "/news",
      });
    }
  } catch { /* ignore source */ }

  const sorted = items
    .filter((it) => it.createdAt)
    .sort((a, b) => Date.parse(String(b.createdAt)) - Date.parse(String(a.createdAt)))
    .slice(0, limit);

  res.json({ feed: sorted });
});

app.get("/api/public/social-gallery/assets/:fileName", (req, res) => {
  try {
    const requested = path.basename(String(req.params.fileName || "").trim());
    if (!requested) {
      res.status(404).end();
      return;
    }

    const assetPath = path.join(SOCIAL_GALLERY_ASSETS_DIR, requested);
    if (!assetPath.startsWith(SOCIAL_GALLERY_ASSETS_DIR) || !fs.existsSync(assetPath)) {
      res.status(404).end();
      return;
    }

    const extension = path.extname(requested).toLowerCase();
    const contentType = extension === ".png"
      ? "image/png"
      : extension === ".webp"
      ? "image/webp"
      : extension === ".gif"
      ? "image/gif"
      : "image/jpeg";

    res.setHeader("Cache-Control", "public, max-age=31536000, immutable");
    res.type(contentType);
    res.sendFile(assetPath);
  } catch {
    res.status(404).end();
  }
});

