app.post("/api/admin/content/:collection", express.json(), async (req, res) => {
  const collection = normalizeAdminText(req.params.collection);
  if (!MANAGED_ADMIN_COLLECTIONS.has(collection)) {
    res.status(404).json({ error: "Collection not found" });
    return;
  }

  const integrations = {};
  let item = upsertManagedAdminCollectionItem(collection, req.body || {});
  if (collection === "activities" && isManagedEventActivity(item)) {
    try {
      const sync = await syncManagedActivityToVamsys(item, { action: "upsert" });
      item = upsertManagedAdminCollectionItem(collection, {
        ...item,
        vamsysId: sync.vamsysId,
        vamsysSection: sync.section,
        vamsysSyncStatus: "synced",
        vamsysSyncError: "",
        vamsysSyncedAt: sync.syncedAt,
      }, item.id);
    } catch (error) {
      item = upsertManagedAdminCollectionItem(collection, {
        ...item,
        vamsysSyncStatus: "failed",
        vamsysSyncError: String(error?.message || error || "vAMSYS sync failed"),
      }, item.id);
    }
  }
  if (collection === "activities" && normalizeAdminBoolean(req.body?.sendToDiscord, false)) {
    void publishNewsToDiscord({
      title: item?.title,
      content: item?.content || item?.summary || item?.description,
      category: item?.category || "News",
      author: item?.author || "Admin",
    }).catch(() => {});
  }
  if (collection === "activities" && normalizeAdminBoolean(req.body?.sendToTelegram, false)) {
    publishActivityToTelegram({
      title: item?.title,
      summary: item?.summary || item?.description,
      category: item?.category,
      published: item?.published,
    });
  }
  if (collection === "activities") {
    const vkRequested = normalizeAdminBoolean(req.body?.sendToVK ?? req.body?.publishToVK, false);
    const vkPlan = getManagedActivityVkPublishPlan(item, req.body || {});
    if (vkPlan.attempted) {
      try {
        integrations.vk = await publishNewsToVk({
          title: item?.title,
          content: item?.content || item?.summary || item?.description,
          category: item?.category || "News",
          author: item?.author || "Admin",
          linkUrl: vkPlan.linkUrl,
          bannerUrl: item?.bannerUrl || item?.imageUrl || item?.image,
        });
      } catch (error) {
        integrations.vk = {
          sent: false,
          attempted: true,
          reason: String(error?.message || error || "vk_publish_failed"),
        };
      }
    } else if (vkRequested) {
      integrations.vk = {
        sent: false,
        attempted: false,
        reason: vkPlan.reason,
      };
    }
    const vkStatePatch = buildManagedActivityVkStatePatch(integrations.vk, vkRequested);
    if (vkStatePatch) {
      item = upsertManagedAdminCollectionItem(collection, {
        ...item,
        ...vkStatePatch,
      }, item.id);
    }
  }
  if (collection === "activities") {
    appendActivityToAiKnowledge(item);
  }
  res.status(201).json({ ok: true, item, integrations });
});

app.put("/api/admin/content/:collection/:id", express.json(), async (req, res) => {
  const collection = normalizeAdminText(req.params.collection);
  if (!MANAGED_ADMIN_COLLECTIONS.has(collection)) {
    res.status(404).json({ error: "Collection not found" });
    return;
  }

  const integrations = {};
  let item = upsertManagedAdminCollectionItem(collection, req.body || {}, req.params.id);
  if (collection === "activities" && isManagedEventActivity(item)) {
    try {
      const sync = await syncManagedActivityToVamsys(item, { action: "upsert" });
      item = upsertManagedAdminCollectionItem(collection, {
        ...item,
        vamsysId: sync.vamsysId,
        vamsysSection: sync.section,
        vamsysSyncStatus: "synced",
        vamsysSyncError: "",
        vamsysSyncedAt: sync.syncedAt,
      }, item.id);
    } catch (error) {
      item = upsertManagedAdminCollectionItem(collection, {
        ...item,
        vamsysSyncStatus: "failed",
        vamsysSyncError: String(error?.message || error || "vAMSYS sync failed"),
      }, item.id);
    }
  }
  if (collection === "activities" && normalizeAdminBoolean(req.body?.sendToDiscord, false)) {
    void publishNewsToDiscord({
      title: item?.title,
      content: item?.content || item?.summary || item?.description,
      category: item?.category || "News",
      author: item?.author || "Admin",
    }).catch(() => {});
  }
  if (collection === "activities" && normalizeAdminBoolean(req.body?.sendToTelegram, false)) {
    publishActivityToTelegram({
      title: item?.title,
      summary: item?.summary || item?.description,
      category: item?.category,
      published: item?.published,
    });
  }
  if (collection === "activities") {
    const vkRequested = normalizeAdminBoolean(req.body?.sendToVK ?? req.body?.publishToVK, false);
    const vkPlan = getManagedActivityVkPublishPlan(item, req.body || {});
    if (vkPlan.attempted) {
      try {
        integrations.vk = await publishNewsToVk({
          title: item?.title,
          content: item?.content || item?.summary || item?.description,
          category: item?.category || "News",
          author: item?.author || "Admin",
          linkUrl: vkPlan.linkUrl,
          bannerUrl: item?.bannerUrl || item?.imageUrl || item?.image,
        });
      } catch (error) {
        integrations.vk = {
          sent: false,
          attempted: true,
          reason: String(error?.message || error || "vk_publish_failed"),
        };
      }
    } else if (vkRequested) {
      integrations.vk = {
        sent: false,
        attempted: false,
        reason: vkPlan.reason,
      };
    }
    const vkStatePatch = buildManagedActivityVkStatePatch(integrations.vk, vkRequested);
    if (vkStatePatch) {
      item = upsertManagedAdminCollectionItem(collection, {
        ...item,
        ...vkStatePatch,
      }, item.id);
    }
  }
  if (collection === "activities") {
    appendActivityToAiKnowledge(item);
  }
  res.json({ ok: true, item, integrations });
});

app.post("/api/admin/content/activities/:id/publish-vk", express.json({ limit: "256kb" }), async (req, res) => {
  const activityId = normalizeAdminText(req.params.id);
  if (!activityId) {
    res.status(400).json({ ok: false, error: "Activity id is required" });
    return;
  }

  let item = getManagedAdminCollectionItem("activities", activityId);
  if (!item) {
    res.status(404).json({ ok: false, error: "Activity not found" });
    return;
  }

  const vkPlan = getManagedActivityVkPublishPlan(item, { sendToVK: true, publishToVK: true });
  let vkResult;
  if (vkPlan.attempted) {
    try {
      vkResult = await publishNewsToVk({
        title: item?.title,
        content: item?.content || item?.summary || item?.description,
        category: item?.category || "News",
        author: item?.author || "Admin",
        linkUrl: vkPlan.linkUrl,
        bannerUrl: item?.bannerUrl || item?.imageUrl || item?.image,
      });
    } catch (error) {
      vkResult = {
        sent: false,
        attempted: true,
        reason: String(error?.message || error || "vk_publish_failed"),
      };
    }
  } else {
    vkResult = {
      sent: false,
      attempted: false,
      reason: vkPlan.reason,
    };
  }

  const vkStatePatch = buildManagedActivityVkStatePatch(vkResult, true);
  if (vkStatePatch) {
    item = upsertManagedAdminCollectionItem("activities", {
      ...item,
      ...vkStatePatch,
    }, item.id);
  }

  if (!vkResult?.sent) {
    res.status(400).json({ ok: false, error: vkResult?.reason || "VK publish failed", result: vkResult, item });
    return;
  }

  res.json({ ok: true, result: vkResult, item });
});

app.delete("/api/admin/content/:collection/:id", async (req, res) => {
  const collection = normalizeAdminText(req.params.collection);
  if (!MANAGED_ADMIN_COLLECTIONS.has(collection)) {
    res.status(404).json({ error: "Collection not found" });
    return;
  }

  const existing = getManagedAdminCollectionItem(collection, req.params.id);
  if (collection === "activities" && isManagedEventActivity(existing || {})) {
    try {
      await syncManagedActivityToVamsys(existing || {}, { action: "delete" });
    } catch (error) {
      res.status(400).json({ ok: false, error: String(error?.message || error || "Failed to delete activity in vAMSYS") });
      return;
    }
  }

  const deleted = deleteManagedAdminCollectionItem(collection, req.params.id);
  if (!deleted) {
    res.status(404).json({ error: "Item not found" });
    return;
  }

  res.json({ ok: true });
});

